CREATE TABLE IF NOT EXISTS attendance (
    id INT AUTO_INCREMENT PRIMARY KEY,
    user_id VARCHAR(255) NOT NULL,
    attendance_date DATE NOT NULL,
    UNIQUE KEY org_emp_date (user_id, attendance_date)
);

CREATE TABLE IF NOT EXISTS admins (
    id INT AUTO_INCREMENT PRIMARY KEY,
    username VARCHAR(255) NOT NULL UNIQUE,
    password VARCHAR(255) NOT NULL
);

CREATE TABLE IF NOT EXISTS users (
    id INT AUTO_INCREMENT PRIMARY KEY,
    username VARCHAR(255) NOT NULL UNIQUE,
    password VARCHAR(255) NOT NULL,
    twofa_secret VARCHAR(255),
    has_2fa_enabled BOOLEAN DEFAULT FALSE
);

CREATE TABLE IF NOT EXISTS teams (
    id INT AUTO_INCREMENT PRIMARY KEY,
    name VARCHAR(255) NOT NULL,
    description TEXT,
    technical_summary TEXT,
    current_objective TEXT
);

CREATE TABLE IF NOT EXISTS individuals (
    id INT AUTO_INCREMENT PRIMARY KEY,
    name VARCHAR(255) NOT NULL,
    role VARCHAR(255),
    team_id INT,
    department VARCHAR(255),
    year_of_study VARCHAR(255),
    studying_year INT,
    daily_work TEXT,
    achievements JSON,
    certificates JSON,
    research_work JSON,
    image TEXT
);

CREATE TABLE IF NOT EXISTS individual_work_logs (
    id INT AUTO_INCREMENT PRIMARY KEY,
    individual_id INT NOT NULL,
    work_date DATE NOT NULL,
    work_text TEXT NOT NULL,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    UNIQUE KEY individual_work_date (individual_id, work_date)
);

CREATE TABLE IF NOT EXISTS upcoming_ctfs (
    id INT AUTO_INCREMENT PRIMARY KEY,
    title VARCHAR(255) NOT NULL,
    url TEXT,
    start_time DATETIME,
    end_time DATETIME,
    format VARCHAR(255),
    location VARCHAR(255),
    description TEXT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS attendance_holidays (
    id INT AUTO_INCREMENT PRIMARY KEY,
    holiday_date DATE NOT NULL UNIQUE,
    title VARCHAR(255) NOT NULL,
    holiday_type VARCHAR(100) DEFAULT 'Institute Holiday',
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS attendance_od (
    id INT AUTO_INCREMENT PRIMARY KEY,
    user_id VARCHAR(255) NOT NULL,
    od_date DATE NOT NULL,
    reason TEXT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    UNIQUE KEY user_od_date (user_id, od_date)
);

CREATE TABLE IF NOT EXISTS projects (
    id VARCHAR(255) PRIMARY KEY,
    title VARCHAR(255) NOT NULL,
    status VARCHAR(50),
    priority VARCHAR(50),
    description TEXT,
    shortDesc TEXT,
    image TEXT,
    stack JSON,
    timeline JSON,
    beneficiaries TEXT,
    team VARCHAR(255),
    usage_desc TEXT,
    operatives JSON
);

CREATE TABLE IF NOT EXISTS cves (
    id INT AUTO_INCREMENT PRIMARY KEY,
    cve_number VARCHAR(255) NOT NULL,
    details TEXT NOT NULL,
    poc TEXT,
    reference_link JSON,
    contributors JSON
);

CREATE TABLE IF NOT EXISTS achievements (
    id INT AUTO_INCREMENT PRIMARY KEY,
    title VARCHAR(255) NOT NULL,
    description TEXT NOT NULL,
    date DATE,
    future_scope TEXT,
    reference_link JSON,
    contributors JSON
);

CREATE TABLE IF NOT EXISTS future_scopes (
    id INT AUTO_INCREMENT PRIMARY KEY,
    title VARCHAR(255) NOT NULL,
    description TEXT,
    expected_outcome TEXT,
    start_date DATE,
    end_date DATE
);

