INSERT INTO teams (`id`, `name`, `description`, `technical_summary`, `current_objective`) VALUES (21, 'Red Team', 'Offensive security and adversary simulation unit for exploitation, infrastructure testing, CVE lab development, and attack-path validation.', 'Builds and validates offensive labs across web exploitation, boot2root, CVE simulation, Active Directory style pivoting, C2/advisory simulations, and controlled infrastructure compromise paths.', 'Lead Incognitrix Range offensive tracks and convert lab findings into safe, repeatable practice environments.');
INSERT INTO teams (`id`, `name`, `description`, `technical_summary`, `current_objective`) VALUES (3, 'Academy Team', 'Learning-content team for Incognitrix Academy modules, roadmaps, guided exercises, and practical cyber security curriculum.', 'Builds markdown-backed learning modules, challenge walkthroughs, learner tracks, and supporting material from lab activity.', 'Turn lab work into reusable practical lessons and structured learning paths.');
INSERT INTO teams (`id`, `name`, `description`, `technical_summary`, `current_objective`) VALUES (2, 'AR VR Team', 'Immersive cyber learning team building AR/VR scenes, network-device visualizations, and interactive security demonstrations.', 'Uses Unity, VR interaction patterns, 3D assets, network-device models, and mixed-reality UI panels for cyber awareness and simulation.', 'Develop immersive modules for cyber games, network architecture visualization, and practical lab demonstrations.');
INSERT INTO teams (`id`, `name`, `description`, `technical_summary`, `current_objective`) VALUES (5, 'Blue Team', 'Defensive operations unit focused on malware analysis, logs, detection engineering, forensics, SIEM, and response workflows.', 'Maintains malware-analysis tasks, Wazuh/EDR monitoring, forensic exercises, incident timelines, and detection content for blue-team learning.', 'Strengthen the Malware Lab, Forensic Challenges, and EDR alerting workflows inside Incognitrix Range.');
INSERT INTO teams (`id`, `name`, `description`, `technical_summary`, `current_objective`) VALUES (7, 'Career Team', 'Career enablement project team for placement preparation, job discovery experiments, and learner career support.', 'Explores job scraping/fetching, placement assessment workflows, and career-oriented automation while staying within platform limits.', 'Support members with placement preparation and practical career tooling.');
INSERT INTO teams (`id`, `name`, `description`, `technical_summary`, `current_objective`) VALUES (6, 'CVE Hunt Team', 'Vulnerability research team responsible for CVE review, reproduction, documentation, and responsible disclosure tracking.', 'Works on CVE labs, vulnerable application analysis, proof validation, mitigation notes, and structured CVE simulation content.', 'Maintain verified CVE records and turn public vulnerabilities into guided simulations for the Range.');
INSERT INTO teams (`id`, `name`, `description`, `technical_summary`, `current_objective`) VALUES (9, 'Escape Room Team', 'Challenge design team for puzzle-driven security rooms, forensic trails, and interactive cyber problem solving.', 'Creates scenario-based tasks with flags, clues, staged evidence, and challenge chains for learner progression.', 'Expand room-style challenges that blend web, forensics, crypto, OSINT, and reverse engineering.');
INSERT INTO teams (`id`, `name`, `description`, `technical_summary`, `current_objective`) VALUES (15, 'Networking Team', 'Networking team responsible for lab network design, cluster operations, and traffic visualization.', 'Networking:
1. Network Architecture: A controlled and restricted lab network where internal systems can reach the internet while external networks cannot access internal lab systems.
2. Load Balancing & Cluster Management: Raspberry Pi cluster with one master and four worker nodes. HAProxy handles load balancing on the master, while JOBE balancer workers handle compilation jobs and return output.
3. Network Dashboard: A dashboard that visualizes lab network architecture and simulates network requests flowing through the lab.', 'Maintain the restricted lab network, Raspberry Pi load-balancing cluster, JOBE compilation workers, and the network simulation dashboard.');
INSERT INTO teams (`id`, `name`, `description`, `technical_summary`, `current_objective`) VALUES (17, 'Portfolio Team', 'Portal and data presentation team for public lab information, projects, teams, individual profiles, CVEs, and achievements.', 'Maintains the React/Express/MySQL portal, dashboard views, database-backed pages, Docker seed data, and Google Sheet import tooling.', 'Keep lab data accurate, portable, and presentable across dashboard, team, project, CVE, and achievement pages.');
INSERT INTO teams (`id`, `name`, `description`, `technical_summary`, `current_objective`) VALUES (18, 'Project Team', 'Project execution group for prototype delivery, hardware-assisted learning, and cross-team implementation tasks.', 'Coordinates project builds, documentation, prototype milestones, and integration between Academy, Range, Portfolio, AR/VR, and Networking work.', 'Move prototypes into usable lab modules and public portfolio records.');
INSERT INTO teams (`id`, `name`, `description`, `technical_summary`, `current_objective`) VALUES (20, 'Range Team', 'Operations team for Incognitrix Range, covering offensive simulations, Pro Labs, Boot2Root, CVE simulations, CTFs, malware labs, forensics, and EDR setups.', 'Runs multi-track practical environments that include adversary simulation, enterprise-like infrastructure compromise, single-machine privilege escalation, and blue-team analysis workflows.', 'Maintain reliable hands-on environments for both offensive and defensive training.');

