INSERT INTO projects (`id`, `title`, `status`, `priority`, `description`, `shortDesc`, `image`, `stack`, `timeline`, `beneficiaries`, `team`, `usage_desc`, `operatives`) VALUES ('PROJ-1', 'Incognitrix Academy', 'ONGOING', 'Academy Team', 'Incognitrix Academy is the practical learning arm of the lab. It contains hands-on modules, guided exercises, challenge walkthroughs, and learner roadmaps that turn lab work into repeatable practice.', 'Practical cyber security learning modules, guided exercises, and learner roadmaps.', '', '["React","Node.js","MySQL","Markdown","Cyber Security Curriculum"]', '[{"desc":"Keerthi Raghavan .K: Collected research paper for reverse engineering to add in Incognitrix academy","phase":"LATEST","title":"Collected research paper for reverse engineering to add in Incognitrix academy","active":true},{"desc":"Keerthi Raghavan .K: Added roadmap content (E86 Assemble basics, general architecture, registers amd the stack) in Incognitrix Academy","phase":"LOGGED","title":"Added roadmap content (E86 Assemble basics, general architecture, registers a...","active":false},{"desc":"Keerthi Raghavan .K: Added: 3 Modules in sherlock lab for malware analysis. Exposed wazhu server for student analysis in Incognitrix range","phase":"LOGGED","title":"Added: 3 Modules in sherlock lab for malware analysis. Exposed wazhu server f...","active":false},{"desc":"Keerthi Raghavan .K: Added: Block Chain Instance. Designed (Sherlock); Reverse Engineering and Binary expliotation module content","phase":"LOGGED","title":"Added: Block Chain Instance. Designed (Sherlock); Reverse Engineering and Bin...","active":false},{"desc":"Kadhiravan. E. G: Content creation on 10+ rooms (Incognitrix Academy)","phase":"LOGGED","title":"Content creation on 10+ rooms (Incognitrix Academy)","active":false},{"desc":"Christ Michael Jeniston. S: Added content (Cryptography) in Incognitrix Academy","phase":"LOGGED","title":"Added content (Cryptography) in Incognitrix Academy","active":false}]', 'Incognitrix lab members and learners', 'Academy Team', 'Used for practical learning, module delivery, challenge walkthroughs, and structured cyber security roadmaps.', '[{"name":"Liyander Rishwanth","role":"Lead Developer"}]');
INSERT INTO projects (`id`, `title`, `status`, `priority`, `description`, `shortDesc`, `image`, `stack`, `timeline`, `beneficiaries`, `team`, `usage_desc`, `operatives`) VALUES ('PROJ-2', 'Incognitrix Range', 'ONGOING', 'Range Team', 'Incognitrix Range provides offensive and defensive practical environments.

Offensive:
1. Advisor Simulation: Purple-team/advisory simulations that model threat actors to test defenses and policies.
2. Pro Labs and Mini Pro Labs: Persistent multi-machine enterprise environments, including Active Directory style pivoting and full infrastructure compromise paths.
3. Boot2Root Machines: Single-target machines where learners gain user access and escalate to root/system.
4. CVE Simulations: Guided labs for specific CVEs, focused on critical vulnerabilities published over the past five years.
5. CTF Challenges: Flag-based challenges across web, forensics, crypto, networking, and reverse engineering.

Blue Teaming:
1. Malware Lab: Controlled sandbox environments for analyzing malicious software behavior, communication, and file changes.
2. Forensic Challenges: Memory dumps, disk images, and logs used to reconstruct breach timelines and identify evidence.
3. EDR Setups: Wazuh-based endpoint detection and response setups with alerting and suspicious-behavior detection.', 'Offensive and blue-team practical range with advisor simulations, pro labs, boot2root, CVE simulations, CTFs, malware lab, forensics, and EDR setups.', '', '["Docker","Linux","Active Directory Labs","Wazuh","CTF Engine","Malware Sandbox","Forensics"]', '[{"desc":"Purple-team/advisory simulations that model threat actors to test defenses and policies.","phase":"OFFENSIVE","title":"Advisor Simulation","active":true},{"desc":"Persistent multi-machine enterprise environments, including Active Directory style pivoting and full infrastructure compromise paths.","phase":"OFFENSIVE","title":"Pro Labs and Mini Pro Labs","active":true},{"desc":"Single-target machines where learners gain user access and escalate to root/system.","phase":"OFFENSIVE","title":"Boot2Root Machines","active":true},{"desc":"Guided labs for specific CVEs, focused on critical vulnerabilities published over the past five years.","phase":"OFFENSIVE","title":"CVE Simulations","active":true},{"desc":"Flag-based challenges across web, forensics, crypto, networking, and reverse engineering.","phase":"OFFENSIVE","title":"CTF Challenges","active":true},{"desc":"Controlled sandbox environments for analyzing malicious software behavior, communication, and file changes.","phase":"BLUE TEAMING","title":"Malware Lab","active":true},{"desc":"Memory dumps, disk images, and logs used to reconstruct breach timelines and identify evidence.","phase":"BLUE TEAMING","title":"Forensic Challenges","active":true},{"desc":"Wazuh-based endpoint detection and response setups with alerting and suspicious-behavior detection.","phase":"BLUE TEAMING","title":"EDR Setups","active":true}]', 'Incognitrix lab members and learners', 'Range Team', 'Used to run practical cyber security training across adversary simulation, infrastructure compromise, CVE reproduction, CTF challenges, malware analysis, forensics, and Wazuh EDR practice.', '[{"name":"Liyander Rishwanth","role":"Lead Developer"},{"name":"Keerthi Ragavan","role":"Product Lead"}]');
