INSERT INTO achievements (`id`, `title`, `description`, `date`, `future_scope`, `reference_link`, `contributors`) VALUES (1, 'ACN CTF', 'Amrita CyberNation (ACN) 2025 was inaugurated at Amrita Vishwa Vidyapeetham, Chennai campus as a cybersecurity-focused event bringing industry and academic voices together. Incognitrix records this result as a podium CTF achievement from the ACN event context.', NULL, 'Document the solved categories and convert the learning into forensic, web, and defensive challenge material for Academy and Range.', '["https://www.factamrita.in/","https://www.amrita.edu/news/amrita-cybernation-2025-inaugurated-at-amrita-vishwa-vidyapeetham-chennai-campus/"]', '["Liyander Rishwanth","Keerthi Ragavan","Micheal"]');
INSERT INTO achievements (`id`, `title`, `description`, `date`, `future_scope`, `reference_link`, `contributors`) VALUES (2, 'L3m0n CTF', 'L3m0n CTF 2025 was a 24-hour Jeopardy-style CTF at Amrita Vishwa Vidyapeetham, Coimbatore, presented by TIFAC-CORE in Cyber Security and Amrita. Public event details list Web, Crypto, Pwn, Reverse, Forensics, Misc, OSINT, and GeoOSINT categories.', NULL, 'Turn the strongest solves into internal writeups and create follow-up CTF challenges across web, crypto, reverse, forensics, and OSINT.', '["https://ctf.l3m0nctf.xyz/"]', '["Liyander Rishwanth","Keerthi Ragavan","Micheal"]');
INSERT INTO achievements (`id`, `title`, `description`, `date`, `future_scope`, `reference_link`, `contributors`) VALUES (3, 'L3m0n CTF', 'L3m0n CTF 2025 was a 24-hour Jeopardy-style CTF at Amrita Vishwa Vidyapeetham, Coimbatore, presented by TIFAC-CORE in Cyber Security and Amrita. Public event details list Web, Crypto, Pwn, Reverse, Forensics, Misc, OSINT, and GeoOSINT categories.', NULL, 'Turn the strongest solves into internal writeups and create follow-up CTF challenges across web, crypto, reverse, forensics, and OSINT.', '["https://ctf.l3m0nctf.xyz/"]', '["Liyander Rishwanth","Keerthi Ragavan","Micheal"]');
INSERT INTO achievements (`id`, `title`, `description`, `date`, `future_scope`, `reference_link`, `contributors`) VALUES (4, '0xti CTF', '0xTi CTF was a 24-hour offline Capture the Flag event at Rajalakshmi Engineering College, Chennai, under HackTiVate/Titanium 2026. Public event details describe beginner-to-expert challenges, teams of 2-3, and a prize pool worth Rs. 1.5 lakhs.', NULL, 'Use the event experience to improve competition readiness, timed CTF workflows, and team coordination for future offline contests.', '["https://unstop.com/college-fests/hactivate-rajalakshmi-engineering-college-rec-chennai-431185/amp"]', '["Liyander Rishwanth","Keerthi Ragavan","Micheal"]');
INSERT INTO achievements (`id`, `title`, `description`, `date`, `future_scope`, `reference_link`, `contributors`) VALUES (5, 'HackQuest', 'HackQuest 2026 was a national-level Capture the Flag/web hacking competition organized by Jamal Mohamed College, Trichy, in collaboration with CyberHeals, according to public achievement/event references.', NULL, 'Build web-hacking practice modules and timed challenge sets based on the techniques exercised during the competition.', '["https://www.linkedin.com/posts/ibby-cyber-security-mentor_hackquest-2k26-report-2-activity-7430122477747376128--wBW","https://1nf1n1ty.team/achievements/"]', '["Liyander Rishwanth L"]');
INSERT INTO achievements (`id`, `title`, `description`, `date`, `future_scope`, `reference_link`, `contributors`) VALUES (6, 'KI CTF', 'KI CTF 2026 was an on-site Jeopardy-style CTF at Kumaraguru College of Technology, Coimbatore, part of Cyber Conclave/Yugam 2026. Public listings mention Web, Pwn, Reverse, Forensics, AI, and Crypto challenge domains.', NULL, 'Expand Range challenge categories with AI, pwn, reverse, web, crypto, and forensic tasks inspired by the event.', '["https://yugam.in/e/cyberconclave","https://www.knowafest.com/explore/events/2026/02/1630-yugam-2026-kumaraguru-college-technology-technical-event-coimbatore"]', '["Liyander Rishwanth","Keerthi Ragavan","Micheal"]');
INSERT INTO achievements (`id`, `title`, `description`, `date`, `future_scope`, `reference_link`, `contributors`) VALUES (7, 'Inno Blitz', 'Inno Blitz 2.0 was a national-level technical event at Sri Ramakrishna Engineering College, Coimbatore, themed around transforming ideas into reality, with project presentation, ideathon, and buildathon-style activities.', NULL, 'Convert the project outcome into a clearer prototype story and connect it with Academy, AR/VR, and Portfolio demonstrations.', '["https://srec.ac.in/events/details/inno-blitz","https://www.knowafest.com/explore/events/2026/03/1403-inno-blitz-2-0-sri-ramakrishna-engineering-college-national-level-technical-event-coimbatore"]', '["Mantra K","Dharshini TR"]');
INSERT INTO achievements (`id`, `title`, `description`, `date`, `future_scope`, `reference_link`, `contributors`) VALUES (8, 'Vulnerability Research Across Major Technology Organizations', 'Liyander Rishwanth L is credited in the lab archive for vulnerability research involving Google, Microsoft, Apple, Cambridge, Oxford, and NASA systems or programs. This record is stored as a lab achievement based on internal/project-provided data.', NULL, 'Maintain evidence, disclosure timelines, acknowledgements, and remediation notes in the lab archive as supporting records become available.', '[]', '["Liyander Rishwanth L"]');
INSERT INTO achievements (`id`, `title`, `description`, `date`, `future_scope`, `reference_link`, `contributors`) VALUES (9, 'AI Exploitation Research in Gemini and Grok', 'Liyander Rishwanth L is credited in the lab archive for AI exploitation research involving Gemini and Grok, focused on identifying abuse paths and security weaknesses in AI-assisted systems.', NULL, 'Turn findings into safe AI security labs covering prompt abuse, tool misuse, guardrail testing, and defensive validation.', '[]', '["Liyander Rishwanth L"]');
INSERT INTO achievements (`id`, `title`, `description`, `date`, `future_scope`, `reference_link`, `contributors`) VALUES (10, 'Black Hat USA Invitation by Microsoft', 'Liyander Rishwanth L was invited by Microsoft to attend Black Hat USA as a security researcher, according to the provided lab record.', NULL, 'Use the invitation and conference exposure to strengthen responsible disclosure practice, research networking, and advanced security training content.', '[]', '["Liyander Rishwanth L"]');
